    input clk,
    input load,
    input shift,
    input [7:0] data_in,
    output [7:0] q );reg [7:0] unused_shift_reg;

always @(posedge clk) begin
    if (load)
        unused_shift_reg <= data_in;
    else if (shift)
        unused_shift_reg <= {unused_shift_reg[6:0], 1'b0};
